type RegisterRequest struct {
    Email    string `json:"email"`
    Password string `json:"password"`
}

func (h *AuthHandler) Register(w http.ResponseWriter, r *http.Request) {
    var req RegisterRequest
    if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
        respondError(w, http.StatusBadRequest, "invalid request body")
        return
    }
    if req.Email == "" || len(req.Password) < 8 {
        respondError(w, http.StatusBadRequest, "email required, password min 8 chars")
        return
    }
    hash, err := bcrypt.GenerateFromPassword([]byte(req.Password), 12)
    if err != nil {
        respondError(w, http.StatusInternalServerError, "internal error")
        return
    }
    user, err := h.repo.CreateUser(r.Context(), req.Email, string(hash))
    if err != nil {
        respondError(w, http.StatusConflict, "email already exists")
        return
    }
    respondJSON(w, http.StatusCreated, map[string]any{"id": user.ID, "email": user.Email})
}

