        claims, ok := r.Context().Value(ClaimsKey).(Claims)
        if !ok || claims.Role != "admin" {
            http.Error(w, `{"error":"forbidden"}`, http.StatusForbidden)
            return
        }
        next.ServeHTTP(w, r)
    })
}

