func (h *AuthHandler) Logout(w http.ResponseWriter, r *http.Request) {
    claims, ok := GetClaims(r.Context())
    if !ok {
        respondError(w, 401, "unauthorized")
        return
    }
    // Delete all refresh tokens for this user
    if err := h.repo.DeleteRefreshTokensByUser(r.Context(), claims.UserID); err != nil {
        respondError(w, 500, "internal error")
        return
    }
    respondJSON(w, 200, map[string]string{"message": "logged out"})
}

func (h *AuthHandler) ForgotPassword(w http.ResponseWriter, r *http.Request) {
    var req struct{ Email string `json:"email"` }
    json.NewDecoder(r.Body).Decode(&req)
    // Always return 200 to prevent email enumeration
    defer respondJSON(w, 200, map[string]string{"message": "if the email exists, a reset link was sent"})
    user, err := h.repo.FindByEmail(r.Context(), req.Email)
    if err != nil || user == nil {
        return
    }
    token, hash, _ := GenerateRefreshToken() // reuse random token generator
    h.repo.CreateResetToken(r.Context(), user.ID, hash, time.Now().Add(1*time.Hour))
    // send email with: https://app.com/reset?token=<token>
}

func (h *AuthHandler) ResetPassword(w http.ResponseWriter, r *http.Request) {
    var req struct {
        Token       string `json:"token"`
        NewPassword string `json:"new_password"`
    }
    json.NewDecoder(r.Body).Decode(&req)
    hash := sha256.Sum256([]byte(req.Token))
    rt, err := h.repo.FindResetToken(r.Context(), hex.EncodeToString(hash[:]))
    if err != nil || rt == nil || rt.ExpiresAt.Before(time.Now()) {
        respondError(w, 400, "invalid or expired token")
        return
    }
    newHash, _ := bcrypt.GenerateFromPassword([]byte(req.NewPassword), 12)
    h.repo.UpdatePassword(r.Context(), rt.UserID, string(newHash))
    h.repo.DeleteResetToken(r.Context(), rt.ID)
    respondJSON(w, 200, map[string]string{"message": "password reset successful"})
}

