func (h *AuthHandler) VerifyEmail(w http.ResponseWriter, r *http.Request) {
    token := r.URL.Query().Get("token")
    if token == "" {
        respondError(w, 400, "token required")
        return
    }
    hash := sha256.Sum256([]byte(token))
    vt, err := h.repo.FindVerificationToken(r.Context(), hex.EncodeToString(hash[:]))
    if err != nil || vt == nil {
        respondError(w, 400, "invalid token")
        return
    }
    h.repo.SetEmailVerified(r.Context(), vt.UserID, true)
    h.repo.DeleteVerificationToken(r.Context(), vt.ID)
    respondJSON(w, 200, map[string]string{"message": "email verified"})
}

