func TestAdminOnly_ValidAdmin(t *testing.T) {
    // Helper to create test JWT
    token := createTestJWT(t, "test-secret", 1, "admin", "a@b.com")

    handler := AuthMiddleware("test-secret")(AdminOnly(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        w.WriteHeader(200)
    })))

    req := httptest.NewRequest("GET", "/", nil)
    req.Header.Set("Authorization", "Bearer "+token)
    rec := httptest.NewRecorder()
    handler.ServeHTTP(rec, req)

    if rec.Code != 200 {
        t.Errorf("expected 200, got %d", rec.Code)
    }
}

func TestAdminOnly_NonAdmin(t *testing.T) {
    token := createTestJWT(t, "test-secret", 1, "user", "a@b.com")
    handler := AuthMiddleware("test-secret")(AdminOnly(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        t.Fatal("should not reach handler")
    })))
    req := httptest.NewRequest("GET", "/", nil)
    req.Header.Set("Authorization", "Bearer "+token)
    rec := httptest.NewRecorder()
    handler.ServeHTTP(rec, req)
    if rec.Code != 403 {
        t.Errorf("expected 403, got %d", rec.Code)
    }
}

